using System.Text.RegularExpressions;

namespace Contoso.Text;

public sealed class StringFormatter
{
    public string FormatPhoneNumber(string digits)
    {
        ArgumentNullException.ThrowIfNull(digits);
        if (digits.Length != 10)
            throw new ArgumentException("Must be exactly 10 digits.", nameof(digits));
        return $"({digits[..3]}) {digits[3..6]}-{digits[6..]}";
    }

    public string BuildGreeting(string name, string title = "Mr.")
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(name);
        return $"Dear {title} {name},";
    }

    public string GenerateSlug(string title)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(title);
        return Regex.Replace(title.Trim().ToLowerInvariant(), @"[^a-z0-9]+", "-").Trim('-');
    }

    public string FormatCurrency(decimal amount, string symbol = "$")
    {
        return $"{symbol}{amount:F2}";
    }
}

using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        StringAssert.StartsWith(result, "(555)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        StringAssert.EndsWith(result, "4567");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    public void FormatPhoneNumber_TooFewDigits_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber("12345"));
    }

    [TestMethod]
    public void FormatPhoneNumber_TooManyDigits_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber("12345678901"));
    }

    [TestMethod]
    public void FormatPhoneNumber_EmptyString_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(""));
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_NameOnly_UsesDefaultTitle()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_NameAndTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Doe", "Ms.");

        StringAssert.StartsWith(result, "Dear ");
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_ContainsName()
    {
        var result = _formatter.BuildGreeting("Anderson", "Prof.");

        StringAssert.Contains(result, "Anderson");
    }

    [TestMethod]
    public void BuildGreeting_NullName_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.BuildGreeting(null!));
    }

    [TestMethod]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting("   "));
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ReplacesThem()
    {
        var result = _formatter.GenerateSlug("C# is great!!!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingTrailingSpaces_TrimsResult()
    {
        var result = _formatter.GenerateSlug("  Hello World  ");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_MultipleConsecutiveSpecialChars_CollapsesToSingleDash()
    {
        var result = _formatter.GenerateSlug("foo---bar   baz");

        Assert.AreEqual("foo-bar-baz", result);
    }

    [TestMethod]
    public void GenerateSlug_MixedCase_ReturnsAllLowercase()
    {
        var result = _formatter.GenerateSlug("MSTest Is Fun");

        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex("^[a-z0-9-]+$"));
    }

    [TestMethod]
    public void GenerateSlug_TitleStartingWithSpecialChars_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("...leading dots");

        Assert.IsFalse(result.StartsWith('-'), "Slug should not start with a dash.");
        StringAssert.StartsWith(result, "leading");
    }

    [TestMethod]
    public void GenerateSlug_TitleEndingWithSpecialChars_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("trailing dots...");

        Assert.IsFalse(result.EndsWith('-'), "Slug should not end with a dash.");
        StringAssert.EndsWith(result, "dots");
    }

    [TestMethod]
    public void GenerateSlug_NullInput_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.GenerateSlug(null!));
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceInput_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug("   "));
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_PositiveAmount_ReturnsFormattedWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.AreEqual("$9.99", result);
    }

    [TestMethod]
    public void FormatCurrency_ZeroAmount_ReturnsZeroFormatted()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_IncludesNegativeSign()
    {
        var result = _formatter.FormatCurrency(-5.50m);

        Assert.AreEqual("$-5.50", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(100m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_AnyAmount_EndsWith2DecimalPlaces()
    {
        var result = _formatter.FormatCurrency(7m, "£");

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(1234.5m, "¥");

        Assert.AreEqual("¥1234.50", result);
    }

    [TestMethod]
    public void FormatCurrency_RoundsToTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(3.999m);

        Assert.AreEqual("$4.00", result);
    }
}

