    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ReplacesThem()
    {
        var result = _formatter.GenerateSlug("C# is great!!!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingTrailingSpaces_TrimsResult()
    {
        var result = _formatter.GenerateSlug("  Hello World  ");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_MultipleConsecutiveSpecialChars_CollapsesToSingleDash()
    {
        var result = _formatter.GenerateSlug("foo---bar   baz");

        Assert.AreEqual("foo-bar-baz", result);
    }

    [TestMethod]
    public void GenerateSlug_MixedCase_ReturnsAllLowercase()
    {
        var result = _formatter.GenerateSlug("MSTest Is Fun");

        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex("^[a-z0-9-]+$"));
    }

    [TestMethod]
    public void GenerateSlug_TitleStartingWithSpecialChars_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("...leading dots");

        Assert.IsFalse(result.StartsWith('-'), "Slug should not start with a dash.");
        StringAssert.StartsWith(result, "leading");
    }

    [TestMethod]
    public void GenerateSlug_TitleEndingWithSpecialChars_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("trailing dots...");

        Assert.IsFalse(result.EndsWith('-'), "Slug should not end with a dash.");
        StringAssert.EndsWith(result, "dots");
    }

