    [TestMethod]
    public void FormatCurrency_PositiveAmount_ReturnsFormattedWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.AreEqual("$9.99", result);
    }

    [TestMethod]
    public void FormatCurrency_ZeroAmount_ReturnsZeroFormatted()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_IncludesNegativeSign()
    {
        var result = _formatter.FormatCurrency(-5.50m);

        Assert.AreEqual("$-5.50", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(100m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_AnyAmount_EndsWith2DecimalPlaces()
    {
        var result = _formatter.FormatCurrency(7m, "£");

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(1234.5m, "¥");

        Assert.AreEqual("¥1234.50", result);
    }

    [TestMethod]
    public void FormatCurrency_RoundsToTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(3.999m);

        Assert.AreEqual("$4.00", result);
    }
}

