         Assert.AreEqual("foo-bar-baz", result);
     }

     [TestMethod]
     public void GenerateSlug_MixedCase_ReturnsAllLowercase()
     {
         var result = _formatter.GenerateSlug("MSTest Is Fun");

         StringAssert.Matches(result, new System.Text.RegularExpressions.Regex("^[a-z0-9-]+$"));
     }

     [TestMethod]
     public void GenerateSlug_TitleStartingWithSpecialChars_DoesNotStartWithDash()
     {
         var result = _formatter.GenerateSlug("...leading dots");

         Assert.DoesNotStartWith(result, "-");
         Assert.StartsWith(result, "leading");
     }

