     public void GenerateSlug_TitleEndingWithSpecialChars_DoesNotEndWithDash()
     {
         var result = _formatter.GenerateSlug("trailing dots...");

         Assert.DoesNotEndWith(result, "-");
         Assert.EndsWith(result, "dots");
     }

